codeExercises.solution:
const getBoardDetailsWithLookup = async (boardId) => {
  const result = await boardModel.aggregate([
    { $match: { _id: new mongoose.Types.ObjectId(boardId) } },
    {
      $lookup: {
        from: 'columns', // Tên collection của column
        localField: '_id',
        foreignField: 'boardId',
        as: 'columns'
      }
    }
  ]);
  return result[0] || null;
};
